const temp = parseFloat(msg.payload);
const MIN = parseFloat(env.get('SENSOR_TEMP_MIN') || '-55');
const MAX = parseFloat(env.get('SENSOR_TEMP_MAX') || '125');

if (isNaN(temp) || temp < MIN || temp > MAX) {
    node.warn('Leitura inválida: ' + msg.payload);
    node.status({fill:'red', shape:'ring', text:'inválida: '+msg.payload});
    return null;
}

const ts  = new Date().toISOString();
const tab = env.get('SHEETS_TAB_READINGS') || 'sensor_readings';

msg.timestamp     = ts;
msg.temperature   = temp;
msg.payload       = [[ts, temp, 'DS18B20']];
msg.sheets_data   = [[ts, temp, 'DS18B20']];
msg.spreadsheetId = env.get('SHEETS_SPREADSHEET_ID');
msg.sheetName     = tab;
msg.range         = tab + '!A:C';
msg._attempts     = 0;

node.status({fill:'green', shape:'dot', text: temp + '°C'});
return msg;

const MAX_Q = parseInt(env.get('QUEUE_MAX_SIZE') || '500');
const queue  = flow.get('queue') || [];

if (!msg._fromRetry) {
    if (queue.length >= MAX_Q) {
        node.warn('Fila cheia! Descartando: ' + msg.timestamp);
        return null;
    }
    queue.push({
        sheets_data:   msg.sheets_data,
        timestamp:     msg.timestamp,
        temperature:   msg.temperature,
        spreadsheetId: msg.spreadsheetId,
        sheetName:     msg.sheetName,
        range:         msg.range,
        attempts:      0
    });
    flow.set('queue', queue);
}

const item = queue[0];
if (!item) return null;

msg.sheets_data   = item.sheets_data;
msg.timestamp     = item.timestamp;
msg.temperature   = item.temperature;
msg.spreadsheetId = item.spreadsheetId;
msg.sheetName     = item.sheetName;
msg.range         = item.range;
msg._attempts     = item.attempts;
msg.payload       = item.sheets_data;

node.status({fill:'blue', shape:'ring', text:'fila: ' + queue.length});
return msg;

const queue = flow.get('queue') || [];
queue.shift();
flow.set('queue', queue);
node.status({fill:'green', shape:'dot', text:'OK | fila: ' + queue.length});
return msg;

const RETRY_MAX   = parseInt(env.get('RETRY_MAX_ATTEMPTS') || '5');
const RETRY_DELAY = parseInt(env.get('RETRY_DELAY_MS')      || '60000');

const queue = flow.get('queue') || [];
const item  = queue[0];
if (!item) return null;

item.attempts = (item.attempts || 0) + 1;
flow.set('queue', queue);

if (item.attempts >= RETRY_MAX) {
    node.warn('Fallback CSV: ' + item.timestamp + ' (tentativas: ' + item.attempts + ')');
    queue.shift();
    flow.set('queue', queue);
    const csvLine = item.timestamp + ',' + item.temperature + ',DS18B20\n';
    const csvMsg  = {
        payload:  csvLine,
        filename: env.get('BUFFER_CSV_PATH') || '/data/buffer.csv'
    };
    node.status({fill:'red', shape:'ring', text:'CSV fallback | fila: ' + queue.length});
    return [null, csvMsg];
}

const retryMsg = {
    payload:       item.sheets_data,
    sheets_data:   item.sheets_data,
    timestamp:     item.timestamp,
    temperature:   item.temperature,
    spreadsheetId: item.spreadsheetId,
    sheetName:     item.sheetName,
    range:         item.range,
    _attempts:     item.attempts,
    _fromRetry:    true
};
node.status({fill:'yellow', shape:'ring', text:'retry ' + item.attempts + '/' + RETRY_MAX});
setTimeout(() => { node.send([retryMsg, null]); }, RETRY_DELAY);
return null;
